// Parsear mensaje de WhatsApp (compatible con Meta/360dialog/Twilio)
const body = $input.first().json;

let from = '', text = '', profileName = '';

// Meta (WhatsApp Cloud API)
if (body.entry) {
  const entry = body.entry?.[0];
  const change = entry?.changes?.[0];
  const msg = change?.value?.messages?.[0];
  from = msg?.from || '';
  text = msg?.text?.body || msg?.button?.text || msg?.interactive?.button_reply?.title || '';
  profileName = change?.value?.contacts?.[0]?.profile?.name || 'Paciente';
}
// Twilio
else if (body.From) {
  from = body.From.replace('whatsapp:', '');
  text = body.Body || '';
  profileName = body.ProfileName || 'Paciente';
}
// 360dialog / genérico
else if (body.messages) {
  const msg = body.messages[0];
  from = msg.from || '';
  text = msg.text?.body || '';
  profileName = body.contacts?.[0]?.profile?.name || 'Paciente';
}

// Configuración del cliente (igual que Telegram, editar por profesional)
const CLIENTE_CONFIG = {
  id: 'fisio-garcia',
  nombre: 'Dr. Juan García',
  especialidad: 'Fisioterapeuta',
  horario: 'Lunes a Viernes 9:00-13:00 y 16:00-20:00',
  telefono: '+34 600 000 000',
  direccion: 'Calle Mayor 12, Valencia',
  form_url: 'https://TU_DOMINIO/form.html?cliente=fisio-garcia',
  servicios: [
    { nombre: 'Primera consulta', duracion: 60, precio: 50 },
    { nombre: 'Sesión de fisioterapia', duracion: 45, precio: 40 }
  ],
  // Para enviar respuestas: número de WhatsApp Business
  wa_phone_id: 'TU_PHONE_NUMBER_ID',
  wa_token: 'TU_ACCESS_TOKEN'
};

return [{ json: { from, text, profileName, clienteConfig: CLIENTE_CONFIG, rawBody: body } }];

