// Enviar respuesta por WhatsApp Cloud API (Meta)
const aiResponse = $('Agente IA WhatsApp').item.json.choices[0].message.content;
const to = $('Parsear Mensaje WhatsApp').item.json.from;
const config = $('Parsear Mensaje WhatsApp').item.json.clienteConfig;

const payload = {
  messaging_product: 'whatsapp',
  to: to,
  type: 'text',
  text: { body: aiResponse }
};

// Llamada a Meta WhatsApp API
const response = await fetch(`https://graph.facebook.com/v19.0/${config.wa_phone_id}/messages`, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${config.wa_token}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(payload)
});

const result = await response.json();
return [{ json: { sent: true, to, message: aiResponse, result } }];
